from flask import Flask, request, jsonify
from kafka import KafkaProducer

app = Flask(__name__)

producer = KafkaProducer(
    bootstrap_servers=["localhost:9092"],
    value_serializer=lambda v: v.encode("utf-8")
)

@app.route("/publish", methods=["POST", "GET"])
def publish():
    topic_name = request.args.get("topic") or request.form.get("topic") or (request.json or {}).get("topic")
    message = request.args.get("message") or request.form.get("message") or (request.json or {}).get("message")

    if not topic_name or message is None:
        return jsonify({"error": "topic and message are required"}), 400

    future = producer.send(topic_name, message)
    record_metadata = future.get(timeout=10)

    return jsonify({
        "status": "published",
        "topic": record_metadata.topic,
        "partition": record_metadata.partition,
        "offset": record_metadata.offset
    })

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)